1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_SIZE = 3;
4	const BLOCK_BASE_PREMIUM = 60;
5	
6	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const withFirstInsurance = (base: number): number =>
18	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
19	
20	const groupBase = (type: string, count: number): number => {
21	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
22	    return withFirstInsurance(BLOCK_BASE_PREMIUM);
23	  }
24	  return count * withFirstInsurance(BASE_PREMIUM[type]);
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const DEDUCTIBLE = 100;
37	
38	export const runScenario = (input: any): { results: unknown[] } => {
39	  const results: unknown[] = [];
40	  const policies: { items: any[]; cap: number; remainingCap: number }[] = [];
41	  for (let stepIndex = 0; stepIndex < input.steps.length; stepIndex++) {
42	    const step = input.steps[stepIndex];
43	    if (step.op === "claim") {
44	      const policy = policies[step.policy];
45	      let totalPayout = 0;
46	      for (const damage of step.incident.damages) {
47	        const policyItem = policy.items.find((it) => it.type === damage.itemType);
48	        let reimbursement = damage.amount;
49	        if (policyItem && policyItem.enchantment >= 8) {
50	          reimbursement = 0.5 * damage.amount;
51	        }
52	        const payout = Math.max(0, reimbursement - DEDUCTIBLE);
53	        totalPayout += payout;
54	      }
55	      const cappedPayout = Math.min(totalPayout, policy.remainingCap);
56	      const flooredPayout = Math.floor(cappedPayout);
57	      policy.remainingCap -= flooredPayout;
58	      results.push({ payout: flooredPayout, remainingCap: policy.remainingCap });
59	      continue;
60	    }
61	    const items: { type: string; cursed?: boolean }[] = step.items;
62	    for (const item of items) {
63	      if (!(item.type in BASE_PREMIUM)) {
64	        throw new Error(`Unknown item type: ${item.type}`);
65	      }
66	    }
67	    const countsByType = new Map<string, number>();
68	    for (const item of items) {
69	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
70	    }
71	    let premium = PROCESSING_FEE;
72	    let policyBase = 0;
73	    for (const [type, count] of countsByType) {
74	      premium += groupBase(type, count);
75	      policyBase += count * BASE_PREMIUM[type];
76	    }
77	    if (input.customer?.yearsWithMHPCO >= 2) {
78	      premium -= 0.2 * policyBase;
79	    }
80	    if (stepIndex >= 1) {
81	      premium -= 0.15 * policyBase;
82	    }
83	    for (const item of items) {
84	      if (item.cursed) {
85	        premium += 0.5 * BASE_PREMIUM[item.type];
86	      }
87	      if ((item as any).enchantment >= 5) {
88	        premium += 0.3 * BASE_PREMIUM[item.type];
89	      }
90	    }
91	    let insuranceSum = 0;
92	    for (const item of items) {
93	      insuranceSum += INSURANCE_VALUE[item.type];
94	    }
95	    const cap = 2 * insuranceSum;
96	    policies.push({ items, cap, remainingCap: cap });
97	    results.push({ premium: Math.ceil(premium) });
98	  }
99	  return { results };
100	};
